solutions.javascript:
// Solution
function validatePortMappings(composeFile) {
  const services = composeFile.services;
  const hostPorts = new Set();
  for (const service in services) {
    for (const port of services[service].port) {
      if (port < 0 || port > 65535) {
        return false;
      }
      if (hostPorts.has(port)) {
        return false;
      }
      hostPorts.add(port);
    }
  }
  return true;
}
return composeFile;

solutions.python:
class Solution:
  def validate_port_mappings(self, compose_file) -> bool:
    services = compose_file.services
    host_ports = set()
    for service in services:
      for port in service.port:
        if port < 0 or port > 65535:
          return False
        if port in host_ports:
          return False
        host_ports.add(port)
    return True
    return False
